    console.log("scwin.sbm_delete_submitdone");
	if (e.responseJSON.resultDataSet[0].Code < 0) return;

    await $c.win.alert("성공적으로 삭제하였습니다");
	scwin.scheduleYn = "N";
	scwin.callYy = "";
	scwin.callNo = "";
